// Фильтруем пользователей, которым сейчас нужно отправить прогноз
const users = $input.all();
const nowUTC = new Date();

const usersToNotify = [];

for (const user of users) {
  const tz = user.json.timezone || 'Europe/Moscow';
  const preferredTime = user.json.preferred_time || '09:00';
  const lastSent = user.json.last_daily_sent || '';

  const userTimeStr = nowUTC.toLocaleTimeString('ru-RU', {
    timeZone: tz,
    hour: '2-digit',
    minute: '2-digit',
    hour12: false
  });

  const userDateStr = nowUTC.toLocaleDateString('ru-RU', {
    timeZone: tz,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit'
  });

  const [curH, curM] = userTimeStr.split(':').map(Number);
  const [prefH, prefM] = preferredTime.split(':').map(Number);

  const curTotalMin = curH * 60 + curM;
  const prefTotalMin = prefH * 60 + prefM;
  const diffMinutes = Math.abs(curTotalMin - prefTotalMin);

  let alreadySentToday = false;
  if (lastSent) {
    const lastSentDate = new Date(lastSent).toLocaleDateString('ru-RU', {
      timeZone: tz,
      year: 'numeric',
      month: '2-digit',
      day: '2-digit'
    });
    alreadySentToday = lastSentDate === userDateStr;
  }

  if (diffMinutes <= 14 && !alreadySentToday) {
    usersToNotify.push({
      json: {
        telegram_id: user.json.telegram_id,
        first_name: user.json.first_name,
        last_name: user.json.last_name,
        birth_date: user.json.birth_date,
        city: user.json.city,
        timezone: tz,
        preferred_time: preferredTime,
        user_current_time: userTimeStr,
        user_current_date: userDateStr
      }
    });
  }
}

if (usersToNotify.length === 0) {
  return [];
}

return usersToNotify;

const output = $input.item.json.output || '';

if (output.includes('ДАННЫЕ_СОБРАНЫ')) {
  // Parse collected data
  const nameMatch = output.match(/имя:\s*(.+)/i);
  const dateMatch = output.match(/дата_рождения:\s*(.+)/i);
  const cityMatch = output.match(/город:\s*(.+)/i);

  const otherName = nameMatch ? nameMatch[1].trim() : '';
  const otherDate = dateMatch ? dateMatch[1].trim() : '';
  const otherCity = cityMatch ? cityMatch[1].trim() : '';

  return [{
    json: {
      ...$input.item.json,
      dataReady: true,
      otherName,
      otherDate,
      otherCity,
      messageToUser: null
    }
  }];
} else {
  // Still collecting — pass through agent's question to user
  return [{
    json: {
      ...$input.item.json,
      dataReady: false,
      messageToUser: output
    }
  }];
}

// Если пользователь нажал "Я подписался", берём current_mode из Sheets
// Иначе используем mode из callback

const callbackData = $('Парсим callback').item.json.callbackData;
const parsedMode = $('Парсим callback').item.json.mode;
const sheetsData = $('Проверяем юзера (callback)').item.json;

let resolvedMode = parsedMode;

if (callbackData === 'check_subscription') {
  resolvedMode = sheetsData.current_mode || '';
}

return [{
  json: {
    ...$('Парсим callback').item.json,
    mode: resolvedMode,
    resolvedFromSheets: callbackData === 'check_subscription'
  }
}];
